function build(w, WG, THREE){
  WG.atmosphere({sky:'#b8a58c', fog:'#8f7f68', ground:'#2e2620'});
  WG.thesis({landform:'flat', topology:'lanes'});
  const sand=WG.flat(0x8a7a5e,{rough:0.95}), bone=WG.flat(0xd9cfae,{rough:0.8}), dark=WG.flat(0x2e2620,{rough:1});
  const g0=WG.box(160,1.4,160,sand); WG.put(g0,0,-0.7,0); WG.surface(g0,160,1.4,160);
  WG.mound(-55,-30,14,4); WG.mound(55,30,14,4);
  for(let i=0;i<7;i++){ const rib=WG.box(1.2,10-Math.abs(i-3)*1.6,1.2,bone); WG.put(rib,-18+i*6,(10-Math.abs(i-3)*1.6)/2,-40,0.12*(i-3)); WG.solid(rib,1.2,10-Math.abs(i-3)*1.6,1.2); }
  for(let s=-1;s<=1;s+=2){ const mesa=WG.box(14,6,14,dark); WG.put(mesa,s*60,3,0); WG.solid(mesa,14,6,14); const ramp=WG.ramp(s*48,0,s>0?-1.57:1.57,10,3,8); }
  WG.ridge(0,52,0,40,10,2.2);
  const rand=WG.rand(7);
  WG.scatter(10,20,70,7,(x,z,i,rnd)=>{ const r=WG.box(2+rnd()*2,1.5+rnd()*2,2+rnd()*2,bone); WG.put(r,x,1,z,rnd()*3); WG.solid(r,3,2.5,3); });
  return w;
}

